import React, { useEffect, useState } from 'react';
import axios from 'axios';

const OIDC_CLIENT_ID = 'your-client-id';
const OIDC_REDIRECT_URI = 'http://localhost:3000/callback';
const OIDC_AUTHORIZATION_ENDPOINT = 'https://your-oidc-provider.com/auth/realms/your-realm/protocol/openid-connect/auth';

const App = () => {
  const [userProfile, setUserProfile] = useState(null);

  useEffect(() => {
    if (window.location.search.includes('code')) {
      handleCallback();
    } else {
      redirectToAuth();
    }
  }, []);

  const redirectToAuth = () => {
    const state = generateState();
    localStorage.setItem('oidc-state', state);
    window.location.href = `${OIDC_AUTHORIZATION_ENDPOINT}?response_type=code&client_id=${OIDC_CLIENT_ID}&redirect_uri=${OIDC_REDIRECT_URI}&state=${state}`;
  };

  const handleCallback = async () => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');

    if (localStorage.getItem('oidc-state') !== state) {
      throw new Error('State mismatch');
    }

    localStorage.removeItem('oidc-state');

    try {
      const response = await axios.post('https://your-oidc-provider.com/auth/realms/your-realm/protocol/openid-connect/token', {
        grant_type: 'authorization_code',
        code,
        redirect_uri: OIDC_REDIRECT_URI,
        client_id: OIDC_CLIENT_ID
      });

      const idToken = response.data.id_token;
      setUserProfile(decodeJwt(idToken));
    } catch (error) {
      console.error('Error handling callback:', error);
    }
  };

  const generateState = () => {
    return Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
  };

  const decodeJwt = (token) => {
    const base64Url = token.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const jsonPayload = decodeURIComponent(atob(base64).split('').map(function(c) {
      return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
    }).join(''));

    return JSON.parse(jsonPayload);
  };

  return (
    <div>
      {userProfile ? (
        <div>Welcome, {userProfile.name}!</div>
      ) : (
        <div>Loading...</div>
      )}
    </div>
  );
};

export default App;